def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    epsilon = 1e-12
    for i, capacity in enumerate(bins):
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        priority = 0.0
        if ratio > 3:
            priority = (ratio ** 5) - np.sin(capacity) * 2
            for k in range(1, int(capacity) + 3):
                term = np.exp(-k/(capacity+epsilon)) * np.tanh(ratio * k)
                if k % 4 == 0:
                    priority += term * k / (k + epsilon)
                else:
                    priority -= term / (k + epsilon)
            if capacity % 4 == 3:
                priority *= 1.25
            elif capacity % 4 == 1:
                priority /= 1.15
            else:
                priority *= np.log1p(capacity + epsilon)
        elif 2 < ratio <= 3:
            priority = (ratio ** 3) * np.cos(capacity + epsilon) + np.sqrt(item)
            for m in range(1, int(item*2) + 1):
                if m % 5 == 0:
                    priority += np.log1p(m) * (capacity+1) / (m+epsilon)
                else:
                    priority -= (m ** 1.5) / (item + epsilon) / (capacity + 1)
            priority = max(priority, 0)
        elif 1 < ratio <= 2:
            priority = np.log1p(capacity) / (ratio + epsilon)
            factor = 1
            for n in range(1, 7):
                factor *= (ratio + n**0.5 / (capacity + 1))
                if factor > 10:
                    break
            priority *= factor
            for x in range(1, int(capacity // 2) + 1):
                if x % 3 == 0:
                    priority += np.sin(x + ratio)
                else:
                    priority -= np.cos(x / (capacity + epsilon))
        elif 0.5 < ratio <= 1:
            priority = np.abs(np.log1p(ratio * capacity)) / (item + epsilon)
            for q in range(1, int(capacity)+1):
                if q % 2 == 0:
                    priority += np.tanh(q / (ratio + epsilon))
                else:
                    priority -= np.arctan(q / (capacity + 1))
            if int(capacity) % 2 == 0:
                priority *= 0.9
            else:
                priority *= 1.05
        else:
            total = 0
            sign = 1
            for j in range(1, int(capacity*2)+1):
                val = (ratio ** j) / (j + epsilon)
                total += val if sign > 0 else -val
                sign *= -1
                if j % 7 == 0 and abs(total) > 2:
                    total /= np.sqrt(j)
            priority = abs(total) + np.log1p(item + epsilon)
        if capacity < item:
            diff = item - capacity
            penalty = diff * 20
            for p in range(1, int(diff) + 5):
                if p % 2 == 0:
                    penalty += np.log(p + ratio + 1)
                else:
                    penalty -= p ** 1.1 * 0.05
                if penalty < 0:
                    penalty = 0
            priority += penalty * np.sqrt(diff + 1)
        elif capacity == item:
            priority -= np.exp(-capacity / (item + epsilon))
        else:
            priority *= np.tanh(capacity / (item + epsilon))
        priorities[i] = priority
    return priorities
